// AssetsConnection is the connection containing edges to Assets.
type AssetsConnection struct {
	Edges      []*AssetsEdge `json:"edges"`
	PageInfo   PageInfo      `json:"pageInfo"`
	TotalCount int           `json:"totalCount"`
}

func (c *AssetsConnection) build(nodes []*Assets, pager *assetsPager, after *Cursor, first *int, before *Cursor, last *int) {
	c.PageInfo.HasNextPage = before != nil
	c.PageInfo.HasPreviousPage = after != nil
	if first != nil && *first+1 == len(nodes) {
		c.PageInfo.HasNextPage = true
		nodes = nodes[:len(nodes)-1]
	} else if last != nil && *last+1 == len(nodes) {
		c.PageInfo.HasPreviousPage = true
		nodes = nodes[:len(nodes)-1]
	}
	var nodeAt func(int) *Assets
	if last != nil {
		n := len(nodes) - 1
		nodeAt = func(i int) *Assets {
			return nodes[n-i]
		}
	} else {
		nodeAt = func(i int) *Assets {
			return nodes[i]
		}
	}
	c.Edges = make([]*AssetsEdge, len(nodes))
	for i := range nodes {
		node := nodeAt(i)
		c.Edges[i] = &AssetsEdge{
			Node:   node,
			Cursor: pager.toCursor(node),
		}
	}
	if l := len(c.Edges); l > 0 {
		c.PageInfo.StartCursor = &c.Edges[0].Cursor
		c.PageInfo.EndCursor = &c.Edges[l-1].Cursor
	}
	if c.TotalCount == 0 {
		c.TotalCount = len(nodes)
	}
}

// AssetsPaginateOption enables pagination customization.
type AssetsPaginateOption func(*assetsPager) error

// WithAssetsOrder configures pagination ordering.
func WithAssetsOrder(order *AssetsOrder) AssetsPaginateOption {
	if order == nil {
		order = DefaultAssetsOrder
	}
	o := *order
	return func(pager *assetsPager) error {
		if err := o.Direction.Validate(); err != nil {
			return err
		}
		if o.Field == nil {
			o.Field = DefaultAssetsOrder.Field
		}
		pager.order = &o
		return nil
	}
}

// WithAssetsFilter configures pagination filter.
func WithAssetsFilter(filter func(*AssetsQuery) (*AssetsQuery, error)) AssetsPaginateOption {
	return func(pager *assetsPager) error {
		if filter == nil {
			return errors.New("AssetsQuery filter cannot be nil")
		}
		pager.filter = filter
		return nil
	}
}

type assetsPager struct {
	reverse bool
	order   *AssetsOrder
	filter  func(*AssetsQuery) (*AssetsQuery, error)
}

func newAssetsPager(opts []AssetsPaginateOption, reverse bool) (*assetsPager, error) {
	pager := &assetsPager{reverse: reverse}
	for _, opt := range opts {
		if err := opt(pager); err != nil {
			return nil, err
		}
	}
	if pager.order == nil {
		pager.order = DefaultAssetsOrder
	}
	return pager, nil
}

func (p *assetsPager) applyFilter(query *AssetsQuery) (*AssetsQuery, error) {
	if p.filter != nil {
		return p.filter(query)
	}
	return query, nil
}

func (p *assetsPager) toCursor(_m *Assets) Cursor {
	return p.order.Field.toCursor(_m)
}

func (p *assetsPager) applyCursors(query *AssetsQuery, after, before *Cursor) (*AssetsQuery, error) {
	direction := p.order.Direction
	if p.reverse {
		direction = direction.Reverse()
	}
	for _, predicate := range entgql.CursorsPredicate(after, before, DefaultAssetsOrder.Field.column, p.order.Field.column, direction) {
		query = query.Where(predicate)
	}
	return query, nil
}

func (p *assetsPager) applyOrder(query *AssetsQuery) *AssetsQuery {
	direction := p.order.Direction
	if p.reverse {
		direction = direction.Reverse()
	}
	query = query.Order(p.order.Field.toTerm(direction.OrderTermOption()))
	if p.order.Field != DefaultAssetsOrder.Field {
		query = query.Order(DefaultAssetsOrder.Field.toTerm(direction.OrderTermOption()))
	}
	if len(query.ctx.Fields) > 0 {
		query.ctx.AppendFieldOnce(p.order.Field.column)
	}
	return query
}

func (p *assetsPager) orderExpr(query *AssetsQuery) sql.Querier {
	direction := p.order.Direction
	if p.reverse {
		direction = direction.Reverse()
	}
	if len(query.ctx.Fields) > 0 {
		query.ctx.AppendFieldOnce(p.order.Field.column)
	}
	return sql.ExprFunc(func(b *sql.Builder) {
		b.Ident(p.order.Field.column).Pad().WriteString(string(direction))
		if p.order.Field != DefaultAssetsOrder.Field {
			b.Comma().Ident(DefaultAssetsOrder.Field.column).Pad().WriteString(string(direction))
		}
	})
}

// Paginate executes the query and returns a relay based cursor connection to Assets.
func (_m *AssetsQuery) Paginate(
	ctx context.Context, after *Cursor, first *int,
	before *Cursor, last *int, opts ...AssetsPaginateOption,
) (*AssetsConnection, error) {
	if err := validateFirstLast(first, last); err != nil {
		return nil, err
	}
	pager, err := newAssetsPager(opts, last != nil)
	if err != nil {
		return nil, err
	}
	if _m, err = pager.applyFilter(_m); err != nil {
		return nil, err
	}
	conn := &AssetsConnection{Edges: []*AssetsEdge{}}
	ignoredEdges := !hasCollectedField(ctx, edgesField)
	if hasCollectedField(ctx, totalCountField) || hasCollectedField(ctx, pageInfoField) {
		hasPagination := after != nil || first != nil || before != nil || last != nil
		if hasPagination || ignoredEdges {
			c := _m.Clone()
			c.ctx.Fields = nil
			if conn.TotalCount, err = c.Count(ctx); err != nil {
				return nil, err
			}
			conn.PageInfo.HasNextPage = first != nil && conn.TotalCount > 0
			conn.PageInfo.HasPreviousPage = last != nil && conn.TotalCount > 0
		}
	}
	if ignoredEdges || (first != nil && *first == 0) || (last != nil && *last == 0) {
		return conn, nil
	}
	if _m, err = pager.applyCursors(_m, after, before); err != nil {
		return nil, err
	}
	limit := paginateLimit(first, last)
	if limit != 0 {
		_m.Limit(limit)
	}
	if field := collectedField(ctx, edgesField, nodeField); field != nil {
		if err := _m.collectField(ctx, limit == 1, graphql.GetOperationContext(ctx), *field, []string{edgesField, nodeField}); err != nil {
			return nil, err
		}
	}
	_m = pager.applyOrder(_m)
	nodes, err := _m.All(ctx)
	if err != nil {
		return nil, err
	}
	conn.build(nodes, pager, after, first, before, last)
	return conn, nil
}

